import{_ as o,o as i,c as t,ai as l}from"./chunks/framework.ampVZV4B.js";const u=JSON.parse('{"title":"会议表达口语模板","description":"","frontmatter":{},"headers":[],"relativePath":"english-speaking/templates-meeting.md","filePath":"english-speaking/templates-meeting.md"}'),a={name:"english-speaking/templates-meeting.md"};function d(c,e,r,s,n,h){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="会议表达口语模板" tabindex="-1">会议表达口语模板 <a class="header-anchor" href="#会议表达口语模板" aria-label="Permalink to “会议表达口语模板”">​</a></h1><blockquote><p>这一篇适合开会时发言、补充、提问、同意、不同意、总结。<br> 会上最重要的是：<strong>短句、清晰、自然接话</strong>。</p></blockquote><hr><h2 id="_1-会议开场-10-句" tabindex="-1">1. 会议开场（10 句） <a class="header-anchor" href="#_1-会议开场-10-句" aria-label="Permalink to “1. 会议开场（10 句）”">​</a></h2><ol><li><code>Let&#39;s get started.</code></li><li><code>Thanks, everyone, for joining.</code></li><li><code>Let&#39;s begin with a quick overview.</code></li><li><code>The purpose of today&#39;s meeting is to discuss this issue.</code></li><li><code>I&#39;ll briefly walk through the current status.</code></li><li><code>Let&#39;s start with the main point.</code></li><li><code>We have a few things to cover today.</code></li><li><code>First, let&#39;s review where we are.</code></li><li><code>I&#39;d like to start with a short update.</code></li><li><code>Let&#39;s go through the agenda together.</code></li></ol><h2 id="_2-补充观点-10-句" tabindex="-1">2. 补充观点（10 句） <a class="header-anchor" href="#_2-补充观点-10-句" aria-label="Permalink to “2. 补充观点（10 句）”">​</a></h2><ol start="11"><li><code>I&#39;d like to add something here.</code></li><li><code>Let me add one more point.</code></li><li><code>I want to build on that.</code></li><li><code>From my perspective, this is important.</code></li><li><code>I think there&#39;s another angle to consider.</code></li><li><code>One thing we should keep in mind is this.</code></li><li><code>I&#39;d also like to point out that...</code></li><li><code>Another thing to consider is the timeline.</code></li><li><code>We should also think about the impact.</code></li><li><code>There&#39;s one more detail I&#39;d like to mention.</code></li></ol><h2 id="_3-提问与确认-10-句" tabindex="-1">3. 提问与确认（10 句） <a class="header-anchor" href="#_3-提问与确认-10-句" aria-label="Permalink to “3. 提问与确认（10 句）”">​</a></h2><ol start="21"><li><code>Could you clarify that?</code></li><li><code>Can you explain that in more detail?</code></li><li><code>What exactly do you mean by that?</code></li><li><code>Do I understand this correctly?</code></li><li><code>Just to confirm, are we saying that...?</code></li><li><code>Could you walk us through that part again?</code></li><li><code>What is the expected outcome here?</code></li><li><code>Who will be responsible for this?</code></li><li><code>When do we need this to be done?</code></li><li><code>What are the next steps?</code></li></ol><h2 id="_4-表达同意-10-句" tabindex="-1">4. 表达同意（10 句） <a class="header-anchor" href="#_4-表达同意-10-句" aria-label="Permalink to “4. 表达同意（10 句）”">​</a></h2><ol start="31"><li><code>I agree with that.</code></li><li><code>That makes sense.</code></li><li><code>I think that&#39;s a good idea.</code></li><li><code>I&#39;m on the same page.</code></li><li><code>That sounds reasonable.</code></li><li><code>I support that approach.</code></li><li><code>I think we&#39;re aligned on this.</code></li><li><code>That&#39;s exactly what I was thinking.</code></li><li><code>I completely agree.</code></li><li><code>That works for me.</code></li></ol><h2 id="_5-表达不同意或保留意见-10-句" tabindex="-1">5. 表达不同意或保留意见（10 句） <a class="header-anchor" href="#_5-表达不同意或保留意见-10-句" aria-label="Permalink to “5. 表达不同意或保留意见（10 句）”">​</a></h2><ol start="41"><li><code>I see your point, but I have a concern.</code></li><li><code>I&#39;m not sure that&#39;s the best option.</code></li><li><code>I think we may need to look at this differently.</code></li><li><code>I understand, but I don&#39;t fully agree.</code></li><li><code>There might be a better way to handle this.</code></li><li><code>I&#39;m a little concerned about the risk.</code></li><li><code>I think we should be careful here.</code></li><li><code>I&#39;d prefer a simpler solution.</code></li><li><code>We may want to revisit this decision.</code></li><li><code>I&#39;m not convinced this will solve the issue.</code></li></ol><h2 id="_6-打断与接回话题-10-句" tabindex="-1">6. 打断与接回话题（10 句） <a class="header-anchor" href="#_6-打断与接回话题-10-句" aria-label="Permalink to “6. 打断与接回话题（10 句）”">​</a></h2><ol start="51"><li><code>Sorry to interrupt, but...</code></li><li><code>Can I jump in for a second?</code></li><li><code>Before we move on, I&#39;d like to mention something.</code></li><li><code>Let me quickly add one thing.</code></li><li><code>Can we go back to the previous point?</code></li><li><code>I&#39;d like to return to the main issue.</code></li><li><code>Let&#39;s stay focused on the key problem.</code></li><li><code>We seem to be getting off track.</code></li><li><code>Can we get back to the original question?</code></li><li><code>Let&#39;s bring the discussion back to the goal.</code></li></ol><h2 id="_7-总结与收尾-10-句" tabindex="-1">7. 总结与收尾（10 句） <a class="header-anchor" href="#_7-总结与收尾-10-句" aria-label="Permalink to “7. 总结与收尾（10 句）”">​</a></h2><ol start="61"><li><code>Let me summarize what we&#39;ve discussed.</code></li><li><code>So here&#39;s the key takeaway.</code></li><li><code>We&#39;ve agreed on the next step.</code></li><li><code>The action items are clear now.</code></li><li><code>I&#39;ll share the summary after the meeting.</code></li><li><code>Let&#39;s follow up on this tomorrow.</code></li><li><code>Thanks for the discussion.</code></li><li><code>I think we made good progress today.</code></li><li><code>Let&#39;s wrap it up here.</code></li><li><code>Thanks, everyone.</code></li></ol><hr><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to “使用建议”">​</a></h2><ul><li>会议表达不需要长句，短句更稳</li><li><code>21-30</code>、<code>31-40</code>、<code>61-70</code> 最值得优先背</li><li>开会前先准备 3 句你一定会用到的话</li></ul>',20)])])}const p=o(a,[["render",d]]);export{u as __pageData,p as default};
